export const CITY_BY_SLUG: Record<string, City> = Object.fromEntries(
  CITIES.map((c) => [c.slug, c]),
);

export const CITIES_BY_PROVINCE: Record<string, City[]> = CITIES.reduce(
  (acc, c) => {
    (acc[c.province] ??= []).push(c);
    return acc;
  },
  {} as Record<string, City[]>,
);
